{
  "name": "Arizona State Health Insurance Assistance Program (SHIP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income or asset limits; open to all Medicare beneficiaries, their families, and caregivers, with support prioritized for those with limited incomes, under age 65 with disabilities, or dually eligible for Medicare and Medicaid[2][3][6]",
    "asset_limits": "No asset limits or tests apply[2][6]",
    "other_requirements": ["Must be a Medicare beneficiary, family member, or caregiver seeking help with Medicare-related issues[1][2][3][5][6]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free one-on-one personalized health insurance counseling and assistance on Medicare benefits, coverage decisions, Medicare Advantage, Part D prescription drugs, Medigap, Medicare Savings Programs (MSP), Medicaid, low-income subsidies (Extra Help), long-term care insurance, appeals, fraud prevention via Senior Medicare Patrol (SMP), outreach presentations, and enrollment events; no fixed dollar amounts or hours, services provided via phone, in-person, or virtually as needed[1][2][3][4][5][6][7]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-800-432-4040[5][6]", "Website intake form: https://azship.org[6]", "In-person or local appointments via regional providers (e.g., SEAGO in Bisbee for 4-county region[7], PCOA at 8467 E Broadway Blvd, Tucson, AZ 85710, (520) 790-7262[8])", "Mail or additional contacts via state office: Division of Aging and Adult Services, Arizona Department of Economic Security, 1789 West Jefferson, Site Code MD6288, Phoenix, AZ 85007[1]"],
    "processing_time": "Counselors return calls or schedule appointments promptly after contact; no formal processing timeline specified[5][6][7]",
    "waitlist": null,
    "forms": ["Intake form on azship.org; no specific numbered application form required for counseling[6]"],
    "documents": ["No specific documents required for initial counseling; may need Medicare card, income details, or plan documents for assistance with applications like MSP or Extra Help[2][4][6]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available across Arizona[1][5]",
    "regional_variations": "Delivered through a statewide network with local providers and Area Agencies on Aging (e.g., SEAGO for southeast counties, PCOA in Pima/Tucson); services are consistent but access points and counselors are regionally based for local Medicare options[4][7][8]",
    "offices_or_providers": ["Statewide helpline and azship.org; local examples: PCOA Tucson (520-790-7262), SEAGO Bisbee; full network via 1-800-432-4040[1][5][6][7][8]"]
  },
  "official_source": "https://azship.org",
  "gotchas": ["Not a direct financial aid or healthcare provider—offers counseling only, not payment for services; people may miss that it helps apply for other programs like MSP (up to $8,400/year savings) or Extra Help; assumes Medicare enrollment—helps check eligibility; regional providers handle local plans, so contact statewide line first[2][4][6]", "Services are free but rely on volunteers/staff availability, potentially leading to call-back delays[2][7]"],
  "data_shape_notes": "no income/asset test; counseling service via statewide network of local providers; prioritizes low-income/disabled but open to all Medicare-related needs; integrates SMP for fraud prevention"
}

{
  "name": "Congregate and Home-Delivered Meals",
  "eligibility": {
    "age": 60,
    "income_limits": "No fixed statewide income limits specified; eligibility prioritizes those with greatest social/economic need (e.g., limited incomes). For financial assistance via Area Agency on Aging (AAA), criteria vary and require screening—no specific dollar amounts or household tables provided. Medicaid/ALTCS may cover for eligible members without stated limits here.",
    "asset_limits": "No asset limits or exemptions specified.",
    "other_requirements": ["60+ years old or 18-59 with disabilities for many programs", "Homebound or unable to prepare meals independently (e.g., due to illness, disability, mobility issues)", "Priority for greatest need: low-income, minorities, rural residents", "Referral often required from AAA, S.A.I.L., or ALTCS case managers"]
  },
  "benefits": {
    "type": "service",
    "value": "Nutritious meals: Home-delivered (e.g., hot entrée in 3-compartment container + cold sack with salad/fruit/dessert; up to 7 meals/week; special diets for medical needs; wellness check on delivery). Congregate: Hot weekday lunches at senior centers for nutrition/socialization. 1 meal = 1 unit service/day max.",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Phone: Area Agency on Aging Helpline at 602-264-4357 or 602-264-HELP (primary contact for eligibility)", "Phone: Local providers e.g., Fountain Hills Community Center 480-816-5229 (Mon-Thu 9am-4pm)", "In-person: Congregate sites e.g., YWCA Glendale (623) 931-7436", "Through case managers: If already AAA/S.A.I.L./ALTCS client"],
    "processing_time": "Not specified",
    "waitlist": "Scheduling varies by provider; not explicitly stated but implied for popular programs",
    "forms": ["No specific form names/numbers identified"],
    "documents": ["Not specified; prepare proof of age, disability, homebound status, or referral if applicable"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Administered via 12 Area Agencies on Aging covering all counties; focused on Maricopa County examples",
    "regional_variations": "Providers differ: YWCA (Glendale home-delivered/congregate), Fountain Hills Community Center (local delivery), Mom's Meals (Medicaid/Medicare). Delivery days/meals vary; e.g., weekdays hot + weekend frozen in some Phoenix areas.",
    "offices_or_providers": ["Area Agency on Aging (statewide helpline)", "YWCA Metropolitan Phoenix (Glendale)", "Fountain Hills Community Center"]
  },
  "official_source": "https://aging.az.gov/ (implied via Area Agency on Aging; specific provider sites like aaaa.org not directly listed)",
  "gotchas": ["Separate eligibility for financial assistance vs. self-pay (e.g., Fountain Hills self-pay: physical condition, post-hospital, caregiver, or 80+)", "Must contact AAA helpline first for screening—not direct provider apply", "Medicaid/ALTCS separate via health plan/case manager", "No same-day congregate + home meals; max 1/day", "Private pay option ~$9.49/meal if ineligible"],
  "data_shape_notes": "Administered regionally via Area Agencies on Aging with local providers; no uniform income table—priority-based; referrals often required; ties to Medicaid/ALTCS for covered members"
}

{
  "name": "Arizona Senior Community Service Employment Program (SCSEP)",
  "eligibility": {
    "age": 55,
    "income_limits": "Family income no more than 125% of the federal poverty level (FPL). Exact 2026 dollar amounts vary by household size; contact local Arizona SCSEP provider (e.g., NICOA) for current HHS poverty guidelines table, as specific figures not listed in sources. For reference, 125% FPL scales with household size (e.g., historically ~$19,000 for 1 person, ~$25,000 for 2; confirm current via provider).[1][2]",
    "asset_limits": "No asset limits mentioned in sources.",
    "other_requirements": ["Unemployed", "Low employment prospects (assessed during application)", "U.S. citizen or authorized to work", "Priority for: veterans/qualified spouses, age 65+, limited English/low literacy, rural residents, disabled, homeless/at risk, failed to find employment via One-Stop system"][2][5]
  },
  "benefits": {
    "type": "employment",
    "value": "Part-time on-the-job training (average 20 hours/week) at community nonprofits/public agencies (e.g., child care, customer service, teachers' aide, computer technician, maintenance, health care); paid highest of federal/state/local minimum wage; skills training (e.g., computer); ~6 months training followed by job placement assistance; access to American Job Centers.",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Contact NICOA SCSEP (administers in Arizona): phone or online form via https://www.nicoa.org/programs/scsep/ and https://www.tfaforms.com/4891021", "Find local SCSEP office via state grantee or national locator (no specific AZ phone listed; call NICOA or DOL at 1-877-US2-JOBS for referral)", "In-person/mail via local provider offices"],
    "processing_time": "Not specified; enrollment if eligible and no waitlist.",
    "waitlist": "Possible waitlist if slots full; varies by location and funding.",
    "forms": ["NICOA SCSEP online application at https://www.tfaforms.com/4891021"],
    "documents": ["Proof of age (ID)", "Proof of income (last 6-12 months: Social Security, SSDI, SSI, disability benefits, etc.)", "Proof of unemployment", "Residency/household size info", "Veteran status if applicable"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available statewide via grantees; open to all eligible, including non-Native Americans.",
    "regional_variations": "Administered by NICOA (focus on American Indian elders but open to all); potential differences in wait times/slots by rural vs. urban or county based on local sub-grantees; contact local office for specifics.",
    "offices_or_providers": ["NICOA (National Indian Council on Aging) for Arizona", "Local SCSEP offices via grantee network"]
  },
  "official_source": "https://www.nicoa.org/programs/scsep/ (Arizona grantee); https://www.dol.gov/agencies/eta/seniors (federal)",
  "gotchas": ["Income is family/household-based at 125% FPL—includes all members, not just applicant; must be currently unemployed (recently employed may not qualify); training is part-time only (~20 hrs/wk, minimum wage—not full income replacement); priority tiers mean non-priority may face longer waits; not guaranteed permanent job, but bridge to employment; open to non-Natives via NICOA but may prioritize AI/AN elders; verify current FPL limits as they update annually."],
  "data_shape_notes": "Federally uniform but locally administered by grantees like NICOA in AZ; income at 125% FPL (household size-based, verify current HHS table); priority enrollment tiers; potential waitlists by region/funding; no asset test."
}
